export default function SettingsModal({
  settingsOpen,
  onClose,
  handleSubmit,
  setShowUserMessage,
}) {
  if (!settingsOpen) {
    return;
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <h2>Settings</h2>
        <form onSubmit={handleSubmit}>
          <label>
            User Messages:
            <input type="checkbox" name="usermessages" onChange={(e) => setShowUserMessage(e.target)}/>
          </label>
          <button type="submit" className="modal-button">
            Save
          </button>
        </form>
      </div>
    </div>
  );
}
